import{_ as e,c as o,o as i,a1 as t}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Primeira Inicialização: Domine o Diretório de Dados | Antigravity Tools","description":"Aprenda localização e gerenciamento de diretório de dados do Antigravity Tools. Domine abrir diretório de dados na página de configurações, limpar logs, rodar em bandeja e início automático, distinguir dois tipos de início automático.","frontmatter":{"title":"Primeira Inicialização: Domine o Diretório de Dados | Antigravity Tools","sidebarTitle":"Encontre o Diretório de Dados","subtitle":"Essencial para Primeira Inicialização: Diretório de Dados, Logs, Bandeja e Início Automático","description":"Aprenda localização e gerenciamento de diretório de dados do Antigravity Tools. Domine abrir diretório de dados na página de configurações, limpar logs, rodar em bandeja e início automático, distinguir dois tipos de início automático.","tags":["Primeira Inicialização","Diretório de Dados","Logs","Bandeja","Início Automático"],"prerequisite":["start-getting-started","start-installation"],"order":3},"headers":[],"relativePath":"pt/lbjlaq/Antigravity-Manager/start/first-run-data/index.md","filePath":"pt/lbjlaq/Antigravity-Manager/start/first-run-data/index.md"}'),r={name:"pt/lbjlaq/Antigravity-Manager/start/first-run-data/index.md"};function s(d,a,n,c,l,u){return i(),o("div",null,[...a[0]||(a[0]=[t(`<h1 id="essencial-para-primeira-inicializacao-diretorio-de-dados-logs-bandeja-e-inicio-automatico" tabindex="-1">Essencial para Primeira Inicialização: Diretório de Dados, Logs, Bandeja e Início Automático <a class="header-anchor" href="#essencial-para-primeira-inicializacao-diretorio-de-dados-logs-bandeja-e-inicio-automatico" aria-label="Permalink to &quot;Essencial para Primeira Inicialização: Diretório de Dados, Logs, Bandeja e Início Automático&quot;">​</a></h1><p>Muitas capacidades &quot;parecem mágica&quot; do Antigravity Tools (pool de contas, cota, monitoramento, estatísticas, rodar em background), no final se baseiam em duas coisas: <strong>diretório de dados</strong> e <strong>logs</strong>. Na primeira vez que rodar, esclareça essas duas partes, depois resolver problemas economizará muito tempo.</p><h2 id="o-que-e-diretorio-de-dados" tabindex="-1">O que é diretório de dados? <a class="header-anchor" href="#o-que-e-diretorio-de-dados" aria-label="Permalink to &quot;O que é diretório de dados?&quot;">​</a></h2><p><strong>Diretório de dados</strong> é a pasta onde o Antigravity Tools salva estado na sua máquina: JSON de contas, arquivos relacionados à cota, arquivos de log, e bancos de dados SQLite do Token Stats/Proxy Monitor ficam todos aqui. Quando você faz backup/migração/solução de problemas, só localize este diretório primeiro, basicamente pode encontrar fonte de dados autoritativa.</p><h2 id="o-que-voce-podera-fazer-apos-completar" tabindex="-1">O que você poderá fazer após completar <a class="header-anchor" href="#o-que-voce-podera-fazer-apos-completar" aria-label="Permalink to &quot;O que você poderá fazer após completar&quot;">​</a></h2><ul><li>Saber onde fica o diretório de dados do Antigravity Tools (e abrir com um clique)</li><li>Esclarecer quais arquivos devem ser backup, quais são logs/cache</li><li>Ao resolver problemas, consegue localizar rapidamente logs e banco de dados de monitoramento</li><li>Entender diferença entre &quot;fechar janela&quot; e &quot;sair do programa&quot; (bandeja residente)</li><li>Distinguir dois tipos de início automático: início automático vs início automático de proxy reverso</li></ul><h2 id="seu-dilema-atual" tabindex="-1">Seu dilema atual <a class="header-anchor" href="#seu-dilema-atual" aria-label="Permalink to &quot;Seu dilema atual&quot;">​</a></h2><ul><li>Você quer backup/migração de contas, mas não sabe onde contas são salvas</li><li>UI relata erro/chamada de proxy reverso falha, mas não encontra logs</li><li>Você fechou janela, pensou que programa saiu, mas ainda está rodando em background</li></ul><h2 id="quando-usar-essa-tecnica" tabindex="-1">Quando usar essa técnica <a class="header-anchor" href="#quando-usar-essa-tecnica" aria-label="Permalink to &quot;Quando usar essa técnica&quot;">​</a></h2><ul><li>Você acabou de instalar Antigravity Tools, quer confirmar &quot;onde dados ficam&quot;</li><li>Você prepara trocar computador/reinstalar sistema, quer primeiro fazer backup de contas e dados estatísticos</li><li>Você precisa resolver problemas: OAuth falha, atualização de cota falha, início de proxy reverso falha, chamada relata 401/429</li></ul><h2 id="🎒-preparacao-antes-de-comecar" tabindex="-1">🎒 Preparação antes de começar <a class="header-anchor" href="#🎒-preparacao-antes-de-comecar" aria-label="Permalink to &quot;🎒 Preparação antes de começar&quot;">​</a></h2><ul><li>Instalou e pode abrir Antigravity Tools</li><li>Você pode entrar na página Settings (entrada de configurações canto superior direito/barra lateral)</li><li>Sua conta de sistema tem permissão para acessar seu próprio diretório Home</li></ul><div class="warning custom-block"><p class="custom-block-title">Lembrete</p><p>Esta lição dirá quais arquivos são &quot;dados reais&quot;, mas não recomenda que você edite manualmente esses arquivos. Para mudar configuração, priorize mudar na UI.</p></div><h2 id="ideia-principal" tabindex="-1">Ideia Principal <a class="header-anchor" href="#ideia-principal" aria-label="Permalink to &quot;Ideia Principal&quot;">​</a></h2><p>Primeiro lembre uma frase:</p><p>&quot;<strong>O diretório de dados é a única fonte de verdade do estado local; logs são a primeira entrada de solução de problemas.</strong>&quot;</p><p>O Antigravity Tools criará diretório de dados <code>.antigravity_tools</code> no seu diretório Home, e colocará contas, logs, banco de estatísticas, etc. (se diretório não existir será criado automaticamente).</p><p>Simultaneamente, por padrão habilita bandeja: quando você fecha janela, programa não sai imediatamente, mas esconde para bandeja, continua rodando em background.</p><h2 id="siga-me" tabindex="-1">Siga-me <a class="header-anchor" href="#siga-me" aria-label="Permalink to &quot;Siga-me&quot;">​</a></h2><h3 id="passo-1-abra-diretorio-de-dados-na-pagina-de-configuracoes" tabindex="-1">Passo 1: Abra diretório de dados na página de configurações <a class="header-anchor" href="#passo-1-abra-diretorio-de-dados-na-pagina-de-configuracoes" aria-label="Permalink to &quot;Passo 1: Abra diretório de dados na página de configurações&quot;">​</a></h3><p><strong>Por que</strong> Primeiro localize precisamente o diretório de dados, depois seja backup ou solução de problemas, há &quot;ponto de apoio&quot;.</p><p>No Antigravity Tools abra Settings, depois mude para Advanced.</p><p>Você verá uma caixa de entrada somente leitura &quot;Diretório de dados&quot; (ela mostrará caminho real), ao lado há um botão abrir.</p><p>Clique no botão abrir.</p><p><strong>Você deve ver</strong>: Gerenciador de arquivos do sistema abre um diretório, caminho algo como <code>~/.antigravity_tools/</code>.</p><h3 id="passo-2-confirme-seu-caminho-de-diretorio-de-dados-cross-platform" tabindex="-1">Passo 2: Confirme seu caminho de diretório de dados (cross-platform) <a class="header-anchor" href="#passo-2-confirme-seu-caminho-de-diretorio-de-dados-cross-platform" aria-label="Permalink to &quot;Passo 2: Confirme seu caminho de diretório de dados (cross-platform)&quot;">​</a></h3><p><strong>Por que</strong> Depois quando você escrever scripts de backup, ou resolver problemas na linha de comando, precisa saber o caminho real deste diretório no seu sistema.</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-b4ylo" id="tab-YwhEPgZ" checked><label data-title="macOS/Linux" for="tab-YwhEPgZ">macOS/Linux</label><input type="radio" name="group-b4ylo" id="tab-cxdh_Sn"><label data-title="Windows" for="tab-cxdh_Sn">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -la</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools&quot;</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$dataDir </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Join-Path</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> $HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;.antigravity_tools&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$dataDir</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Get-ChildItem</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Force $dataDir</span></span></code></pre></div></div></div><p><strong>Você deve ver</strong>: Diretório existe (se você abre página de configurações pela primeira vez, diretório será criado automaticamente).</p><h3 id="passo-3-conheca-arquivos-principais-no-diretorio-de-dados" tabindex="-1">Passo 3: Conheça &quot;arquivos principais&quot; no diretório de dados <a class="header-anchor" href="#passo-3-conheca-arquivos-principais-no-diretorio-de-dados" aria-label="Permalink to &quot;Passo 3: Conheça &quot;arquivos principais&quot; no diretório de dados&quot;">​</a></h3><p><strong>Por que</strong> Nem todos os arquivos valem ser backup. Primeiro separe &quot;quais são dados de conta&quot;, &quot;quais são banco estatístico/logs&quot;.</p><p>Abaixo nomes de arquivos vêm de código-fonte do projeto, todos são fixos:</p><table tabindex="0"><thead><tr><th>Você verá conteúdo</th><th>Finalidade</th><th>O que você precisa se importar</th></tr></thead><tbody><tr><td><code>accounts.json</code></td><td>Índice de contas (incluindo lista de contas/conta atual)</td><td>Recomendado fazer backup junto ao migrar contas</td></tr><tr><td><code>accounts/</code></td><td>Cada conta um arquivo <code>*.json</code></td><td>Este é corpo principal de dados de conta</td></tr><tr><td><code>logs/</code></td><td>Diretório de logs do aplicativo</td><td>Prioridade ao resolver problemas</td></tr><tr><td><code>token_stats.db</code></td><td>Banco de dados SQLite do Token Stats</td><td>Dados que você vê na página Token Stats vêm dele</td></tr><tr><td><code>proxy_logs.db</code></td><td>Banco de dados SQLite do Proxy Monitor</td><td>Logs de solicitação que você vê na página Monitor vêm dele</td></tr><tr><td><code>warmup_history.json</code></td><td>Histórico local do Smart Warmup</td><td>Principalmente para evitar warmup repetido</td></tr><tr><td><code>update_settings.json</code></td><td>Configurações de verificação de atualização (verificação automática/intervalo etc.)</td><td>Geralmente não precisa mexer manualmente</td></tr></tbody></table><p><strong>Você deve ver</strong>: Pelo menos há diretório <code>logs/</code>; se você ainda não adicionou conta, <code>accounts.json</code>/<code>accounts/</code> podem não ter aparecido.</p><h3 id="passo-4-lembre-localizacao-dos-logs-solucao-de-problemas-depende-disso" tabindex="-1">Passo 4: Lembre localização dos logs (solução de problemas depende disso) <a class="header-anchor" href="#passo-4-lembre-localizacao-dos-logs-solucao-de-problemas-depende-disso" aria-label="Permalink to &quot;Passo 4: Lembre localização dos logs (solução de problemas depende disso)&quot;">​</a></h3><p><strong>Por que</strong> Avisos de erro de UI geralmente só dão &quot;fenômeno&quot;, causa real de falha (ex: solicitação falhou, falha de leitura/escrita de arquivo) muitas vezes está em logs.</p><p>O Antigravity Tools escreve logs em <code>logs/</code> dentro do diretório de dados.</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-SJiD8" id="tab-tMYRYtW" checked><label data-title="macOS/Linux" for="tab-tMYRYtW">macOS/Linux</label><input type="radio" name="group-SJiD8" id="tab-1v6NnLZ"><label data-title="Windows" for="tab-1v6NnLZ">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -la</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools/logs&quot;</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Get-ChildItem</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Force (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Join-Path</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> $HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;.antigravity_tools\\logs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></div></div><p><strong>Você deve ver</strong>: Sob diretório existem arquivos de log rodando por dia (nome de arquivo começa com <code>app.log</code>).</p><h3 id="passo-5-quando-precisa-limpar-logs-use-limpeza-com-um-clique-da-pagina-de-configuracoes" tabindex="-1">Passo 5: Quando precisa &quot;limpar logs&quot;, use limpeza com um clique da página de configurações <a class="header-anchor" href="#passo-5-quando-precisa-limpar-logs-use-limpeza-com-um-clique-da-pagina-de-configuracoes" aria-label="Permalink to &quot;Passo 5: Quando precisa &quot;limpar logs&quot;, use limpeza com um clique da página de configurações&quot;">​</a></h3><p><strong>Por que</strong> Alguns problemas você só quer reproduzir uma vez, depois deixar aqueles logs separadamente; então primeiro limpar logs é melhor para comparar.</p><p>Em Settings -&gt; Advanced, encontre área de logs, clique &quot;Limpar Logs&quot;.</p><p><strong>Você deve ver</strong>: Surge caixa de confirmação; após confirmar avisa limpeza bem-sucedida.</p><div class="tip custom-block"><p class="custom-block-title">Duas coisas com as quais você se preocupará</p><ul><li>Logs farão automaticamente &quot;rodar por dia&quot;, e ao iniciar tentarão limpar logs antigos com mais de 7 dias.</li><li>&quot;Limpar Logs&quot; truncará arquivos de log para 0 bytes, conveniente para processo rodando continuar escrevendo mesmo handle de arquivo.</li></ul></div><h3 id="passo-6-esclareca-diferenca-entre-fechar-janela-e-sair-do-programa-bandeja" tabindex="-1">Passo 6: Esclareça diferença entre &quot;fechar janela&quot; e &quot;sair do programa&quot; (bandeja) <a class="header-anchor" href="#passo-6-esclareca-diferenca-entre-fechar-janela-e-sair-do-programa-bandeja" aria-label="Permalink to &quot;Passo 6: Esclareça diferença entre &quot;fechar janela&quot; e &quot;sair do programa&quot; (bandeja)&quot;">​</a></h3><p><strong>Por que</strong> Antigravity Tools por padrão habilita bandeja; quando você clica fechar no canto superior direito da janela, programa esconderá para bandeja e continuará rodando. Se você acha que ele saiu, facilmente aparece ilusão de &quot;porta ainda ocupada/background ainda rodando&quot;.</p><p>Você pode usar este pequeno fluxo para confirmar:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Operação: fechar janela (não sair)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  Passo 1                Passo 2                             │</span></span>
<span class="line"><span>│  Clique fechar janela →   Vá para bandeja/barra de menu do sistema procurar ícone  │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Você deve ver: ícone da bandeja ainda existe, clicar nele pode mostrar janela novamente.</span></span></code></pre></div><p>No menu da bandeja também há duas ações comuns (muito conveniente quando não vai pela UI):</p><ul><li>Alternar conta: mudar para próxima conta</li><li>Atualizar cota: atualizar cota da conta atual (enquanto notificará frontend atualizar exibição)</li></ul><h3 id="passo-7-configure-inicio-automatico-ao-ligar-deixe-iniciar-minimizado-automaticamente" tabindex="-1">Passo 7: Configure início automático ao ligar (deixe iniciar minimizado automaticamente) <a class="header-anchor" href="#passo-7-configure-inicio-automatico-ao-ligar-deixe-iniciar-minimizado-automaticamente" aria-label="Permalink to &quot;Passo 7: Configure início automático ao ligar (deixe iniciar minimizado automaticamente)&quot;">​</a></h3><p><strong>Por que</strong> Se você quer que funcione como &quot;serviço residente&quot; (bandeja residente + atualização em background), início automático ao ligar economizará cada vez abrir manualmente.</p><p>Em Settings -&gt; General encontre &quot;Início Automático ao Ligado&quot;, escolha habilitar.</p><p><strong>Você deve ver</strong>: Após alternar avisa habilitar com sucesso; próxima vez ao iniciar o sistema rodará com parâmetro <code>--minimized</code>.</p><div class="info custom-block"><p class="custom-block-title">Dois tipos de &quot;início automático&quot;, não confunda</p><table tabindex="0"><thead><tr><th>Nome</th><th>Significado</th><th>Evidência</th></tr></thead><tbody><tr><td>Início automático ao ligar</td><td>Após iniciar computador, inicia Antigravity Tools automaticamente (aplicativo de desktop em si)</td><td>Parâmetros de início incluem <code>--minimized</code>, e fornece comando <code>toggle_auto_launch</code></td></tr><tr><td>Início automático de proxy reverso</td><td>Após Antigravity Tools iniciar, se configurado <code>proxy.auto_start=true</code>, tentará iniciar serviço de proxy reverso local automaticamente</td><td>Ao iniciar aplicativo lê configuração e <code>start_proxy_service(...)</code></td></tr></tbody></table></div><h2 id="ponto-de-verificacao-✅" tabindex="-1">Ponto de verificação ✅ <a class="header-anchor" href="#ponto-de-verificacao-✅" aria-label="Permalink to &quot;Ponto de verificação ✅&quot;">​</a></h2><ul><li>[ ] Você pode ver caminho real do diretório de dados em Settings -&gt; Advanced</li><li>[ ] Você pode abrir diretório de dados, e aproximadamente reconhecer <code>accounts.json</code>, <code>accounts/</code>, <code>logs/</code>, <code>token_stats.db</code>, <code>proxy_logs.db</code></li><li>[ ] Você sabe logs estão em <code>logs/</code>, e pode usar linha de comando para ver rápido</li><li>[ ] Você sabe após fechar janela programa ainda está na bandeja, sair usa Quit do menu da bandeja</li><li>[ ] Você pode distinguir &quot;início automático ao ligar&quot; e &quot;início automático de proxy reverso&quot;</li></ul><h2 id="aviso-sobre-armadilhas" tabindex="-1">Aviso sobre armadilhas <a class="header-anchor" href="#aviso-sobre-armadilhas" aria-label="Permalink to &quot;Aviso sobre armadilhas&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Cenário</th><th>O que você pode fazer (❌)</th><th>Prática recomendada (✓)</th></tr></thead><tbody><tr><td>Não encontra diretório de dados</td><td>Procurar aleatoriamente por diretório de instalação do App no sistema</td><td>Vá diretamente Settings -&gt; Advanced ver &quot;Diretório de dados&quot; e abrir com um clique</td></tr><tr><td>Fechou janela achando que saiu</td><td>Após clicar fechar janela vai mudar configuração/mudar porta</td><td>Primeiro veja se ícone da bandeja ainda existe; para sair use Quit da bandeja</td></tr><tr><td>Muitos logs difíceis de resolver</td><td>Reproduzir problema enquanto folheia logs antigos</td><td>Primeiro &quot;Limpar Logs&quot;, depois reproduzir uma vez, finalmente só ver arquivo de log desta vez</td></tr><tr><td>Quer mudar dados de conta</td><td>Editar manualmente <code>accounts/*.json</code></td><td>Use fluxo de importar/exportar/migrar da UI (próxima seção relacionada explicará)</td></tr></tbody></table><h2 id="resumo-da-licao" tabindex="-1">Resumo da lição <a class="header-anchor" href="#resumo-da-licao" aria-label="Permalink to &quot;Resumo da lição&quot;">​</a></h2><ul><li>Diretório de dados fixo em <code>.antigravity_tools</code> sob Home (no macOS/Linux geralmente se apresenta como diretório oculto), contas/logs/banco estatístico estão todos aqui</li><li>Diretório de logs é <code>logs/</code>, prioridade ao resolver problemas; quando necessário pode limpar com um clique na página de configurações</li><li>Fechar janela esconderá para bandeja continua rodando; para sair completamente use Quit da bandeja</li><li>Início automático tem dois tipos: início automático ao ligar (aplicativo) e início automático de proxy reverso (Proxy)</li></ul><hr><h2 id="proximo-aviso-de-licao" tabindex="-1">Próximo aviso de lição <a class="header-anchor" href="#proximo-aviso-de-licao" aria-label="Permalink to &quot;Próximo aviso de lição&quot;">​</a></h2><blockquote><p>Na próxima lição aprendemos <strong><a href="./../add-account/">Adicionar Contas: Canais Duplos OAuth/Refresh Token e Melhores Práticas</a></strong>.</p></blockquote><hr><h2 id="apendice-referencia-de-codigo-fonte" tabindex="-1">Apêndice: Referência de código-fonte <a class="header-anchor" href="#apendice-referencia-de-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência de código-fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir localização do código-fonte</strong></summary><blockquote><p>Atualizado em: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do arquivo</th><th>Linha</th></tr></thead><tbody><tr><td>Localização do diretório de dados (<code>~/.antigravity_tools</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/account.rs#L16-L33" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/account.rs</code></a></td><td>16-33</td></tr><tr><td>Índice de contas e diretório de arquivos de contas (<code>accounts.json</code> / <code>accounts/</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/account.rs#L16-L46" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/account.rs</code></a></td><td>16-46</td></tr><tr><td>Diretório de logs e rodar por dia (<code>logs/</code> + <code>app.log</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/logger.rs#L17-L83" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/logger.rs</code></a></td><td>17-83</td></tr><tr><td>Limpar logs (truncar arquivo)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/logger.rs#L149-L169" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/logger.rs</code></a></td><td>149-169</td></tr><tr><td>Página de configurações mostra diretório de dados + abrir com um clique</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L525-L576" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>525-576</td></tr><tr><td>Página de configurações limpar logs com um clique (botão + lógica de diálogo)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L127-L135" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>127-135</td></tr><tr><td>Página de configurações limpar logs com um clique (botão aba Advanced)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L732-L747" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>732-747</td></tr><tr><td>Menu da bandeja e eventos de clique (alternar conta/atualizar/mostrar/sair)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/tray.rs#L9-L158" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/tray.rs</code></a></td><td>9-158</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Interruptor de início automático ao ligar (<code>toggle_auto_launch</code> / <code>is_auto_launch_enabled</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/autostart.rs#L4-L39" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/autostart.rs</code></a></td><td>4-39</td></tr><tr><td>Comandos abrir diretório de dados / obter caminho / limpar logs</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L578-L621" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>578-621</td></tr><tr><td>Nome do arquivo do banco de dados Token Stats (<code>token_stats.db</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L58-L61" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>58-61</td></tr><tr><td>Nome do arquivo do banco de dados Proxy Monitor (<code>proxy_logs.db</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/proxy_db.rs#L5-L8" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/proxy_db.rs</code></a></td><td>5-8</td></tr><tr><td>Nome do arquivo de histórico Warmup (<code>warmup_history.json</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/scheduler.rs#L14-L17" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/scheduler.rs</code></a></td><td>14-17</td></tr><tr><td>Nome do arquivo de configurações de atualização (<code>update_settings.json</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/update_checker.rs#L150-L177" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/update_checker.rs</code></a></td><td>150-177</td></tr><tr><td>Início automático de proxy reverso (inicia serviço quando <code>proxy.auto_start=true</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/lib.rs#L107-L126" target="_blank" rel="noreferrer"><code>src-tauri/src/lib.rs</code></a></td><td>107-126</td></tr></tbody></table></details>`,67)])])}const h=e(r,[["render",s]]);export{m as __pageData,h as default};
